// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package validationimport (	"fmt"	"time"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/schema")// IsDayOfTheWeek is a SchemaValidatech tests if the provided value is of type string a valid english day of the week IsDayOfTheWeek(ignoreCase bool) schema.SchemaValidate {	return StringInSlice([]string{		"Monday",		"Tuesday",		"Wednesday",		"Thursday",		"Friday",		"Saturday",		"Sunday",	}, ignoreCase)// IsMonth is a SchemaValidate which tests if the provided value is of type string and a valid english month IsMonth(ignoreCase bool) schema.SchemaValidate {	return StringInSlice([]string{		"January",		"February",		"March",		"April",		"May",		"June",		"July",		"August",		"September",		"October",ovember",		"December",	}, ignoreCase)}// IsRFC3339Time is a SchemaValidate which tests if the provided value is of type string and a valid RFC33349Time IsRFC3339Time(i interface{}, k string) (warnings []string, errors []error) {	v, ok := i.(string)	if !ok {		errors = append(errors, fmt.Errorf("expected type of %q to be string", k))		return warnings, errors	}	if _, err := time.Parse(time.RFC3339, v); err != nil {		errors = append(errors, fmt.Errorf("expected %q to be a valid RFC3339 date, got %q: %+v", k, i, err))	}	return warnings, errors}